const menuBtn=document.querySelector(".btn_menu"),closeBtn=document.querySelector(".btn_close"),links=document.querySelectorAll(".menu__link"),menu=document.querySelector(".menu"),modal=document.querySelector(".modal"),overlay=document.querySelector(".overlay"),modalCloseBtn=document.querySelector(".modal__close"),orderBtns=document.querySelectorAll(".btn_order"),submitModal=document.querySelector(".submit-modal"),quantityBtn=document.querySelectorAll(".btn_quantity"),submitBtn=document.querySelector(".btn_submit"),thanksMsg=document.querySelector(".thanks");function openMenu(){menu.style.top=0}function closeMenu(){menu.style.top="-100%"}function openModal(){modal.style.display="block",overlay.style.display="block"}function closeModal(){modal.style.display="none",overlay.style.display="none"}function sayThanks(){thanksMsg.classList.add("thanks_active")}function closeSayThanks(){thanksMsg.classList.remove("thanks_active")}menuBtn.addEventListener("click",openMenu),closeBtn.addEventListener("click",closeMenu),links.forEach(e=>{e.addEventListener("click",closeMenu)}),orderBtns.forEach(e=>{e.addEventListener("click",openModal)}),modalCloseBtn.addEventListener("click",closeModal),quantityBtn.forEach(e=>{e.addEventListener("click",()=>{quantityBtn.forEach(e=>{e.classList.remove("btn_quantity_active")}),e.classList.toggle("btn_quantity_active")})}),submitBtn.addEventListener("click",e=>{closeModal(),setTimeout(sayThanks,500),setTimeout(closeSayThanks,7e3)});